export type PersonStatus = 'ok' | 'in_progress' | 'overdue'

export interface UserPflichtSummary {
  employee_id: string; user_id: string; email: string; full_name: string
  department: string; position: string; role: UserRole
  total: number; completed: number; in_progress: number; assigned: number; overdue: number
  rate: number; status: PersonStatus
}

const isOverdue = (e: Enrollment) =>
  e.status === 'expired' ||
  (e.status !== 'completed' && !!e.due_date && new Date(e.due_date) < new Date())

export function getEnrollmentsForUser(email: string): Enrollment[] {
  const a = AARE_PFLICHT_ASSIGNMENTS.find(x => x.email.toLowerCase() === email.toLowerCase())
  if (!a) return []
  return AARE_ENROLLMENTS.filter(e => e.user_id === a.user_id)
}

export function getUserPflichtSummary(a: PflichtAssignment): UserPflichtSummary {
  const ens = AARE_ENROLLMENTS.filter(e => e.user_id === a.user_id)
  const completed = ens.filter(e => e.status === 'completed').length
  const overdue = ens.filter(isOverdue).length
  const in_progress = ens.filter(e => e.status === 'in_progress').length
  const assigned = ens.filter(e => e.status === 'assigned').length
  const total = ens.length
  const rate = total ? Math.round((completed / total) * 100) : 100
  const status: PersonStatus = overdue > 0 ? 'overdue' : (completed === total ? 'ok' : 'in_progress')
  return { employee_id: a.employee_id, user_id: a.user_id, email: a.email, full_name: a.full_name,
    department: a.department, position: a.position, role: a.role,
    total, completed, in_progress, assigned, overdue, rate, status }
}

export function getAllUserSummaries(): UserPflichtSummary[] {
  return AARE_PFLICHT_ASSIGNMENTS.map(getUserPflichtSummary)
}

export function getComplianceKpis() {
  const total = AARE_ENROLLMENTS.length
  const completed = AARE_ENROLLMENTS.filter(e => e.status === 'completed').length
  const in_progress = AARE_ENROLLMENTS.filter(e => e.status === 'in_progress').length
  const overdue = AARE_ENROLLMENTS.filter(isOverdue).length
  const summaries = getAllUserSummaries()
  return { total, completed, in_progress, overdue,
    rate: total ? Math.round((completed / total) * 100) : 0,
    people: summaries.length,
    peopleOverdue: summaries.filter(s => s.status === 'overdue').length,
    peopleOk: summaries.filter(s => s.status === 'ok').length }
}

export interface TrainingBreakdownRow {
  code: string; name: string; type: string; cadence: string
  assigned: number; completed: number; overdue: number; rate: number
}

export function getTrainingBreakdown(): TrainingBreakdownRow[] {
  return AARE_PFLICHT_CATALOG.map(t => {
    const ens = AARE_ENROLLMENTS.filter(e => e.course_id === t.code)
    const completed = ens.filter(e => e.status === 'completed').length
    const overdue = ens.filter(isOverdue).length
    return { code: t.code, name: t.name, type: t.type, cadence: t.cadence,
      assigned: ens.length, completed, overdue,
      rate: ens.length ? Math.round((completed / ens.length) * 100) : 0 }
  }).filter(r => r.assigned > 0)
}

export function getPflichtCodesForUser(email: string): string[] {
  const a = AARE_PFLICHT_ASSIGNMENTS.find(x => x.email.toLowerCase() === email.toLowerCase())
  return a ? a.codes : []
}
export function getPflichtTraining(code: string): PflichtTraining | undefined {
  return AARE_PFLICHT_CATALOG.find(t => t.code === code)
}
export function isEnrollmentOverdue(e: Enrollment): boolean { return isOverdue(e) }
